// ============================================================
// ST JOBS BACKFILL v1 — Self-triggering page processor
// Fixes: page cursor always advances, graceful BU fallback,
//        per-job error isolation
// ============================================================

const NEON_URL = 'https://ep-crimson-bar-aetz67os.c-2.us-east-2.aws.neon.tech/sql';
const NEON_CONN = 'postgresql://neondb_owner:npg_OYkCRU4aze2l@ep-crimson-bar-aetz67os.c-2.us-east-2.aws.neon.tech/neondb';
const ST_CLIENT_ID = 'cid.n4ndqmjxyqvklyrzm0t04nndl';
const ST_CLIENT_SECRET = 'cs3.d3ds63u40l7l7w5vit2xyhkgdw8zu7drsg2kwkvou8ddntxkci';
const ST_APP_KEY = 'ak1.tku36dgmajp842ozaxunmu2z8';
const ST_TENANT = '786349683';
const PAGE_SIZE = 50;
const POLL_KEY = 'st_jobs_backfill';

const EXCLUDED_BU_IDS = new Set(['1000003', '40473564']);
const EXCLUDED_JOB_TYPE_IDS = new Set(['40464382', '40464866', '40472671', '40474204', '40466532']);

const BU_TRACK_MAP = {
  '40464378': 'service',
  '40472669': 'service',
  '44662719': 'install',
  '44663237': 'service',
  '44663388': 'install',
  '44663626': 'service',
  '44663783': 'service',
  '44664003': 'install',
  '44664189': 'service',
  '44664642': 'service',
  '44665021': 'service',
  '44665160': 'install',
  '44665308': 'install',
  '44665438': 'service',
  '44667199': 'install'
};

async function neonQuery(sql) {
  const resp = await $helpers.httpRequest({
    method: 'POST',
    url: NEON_URL,
    headers: { 'Neon-Connection-String': NEON_CONN, 'Content-Type': 'application/json' },
    body: JSON.stringify({ query: sql }),
    returnFullResponse: false
  });
  return typeof resp === 'string' ? JSON.parse(resp) : resp;
}

// Refresh ST token
const tokenResp = await $helpers.httpRequest({
  method: 'POST',
  url: 'https://auth.servicetitan.io/connect/token',
  headers: { 'Content-Type': 'application/x-www-form-urlencoded' },
  body: `grant_type=client_credentials&client_id=${ST_CLIENT_ID}&client_secret=${ST_CLIENT_SECRET}`,
  returnFullResponse: false
});
const stToken = (typeof tokenResp === 'string' ? JSON.parse(tokenResp) : tokenResp).access_token;

// Read current page
const stateResult = await neonQuery(`SELECT COALESCE(metadata->>'page', '1')::int AS page FROM spartan_ops.poll_state WHERE poll_key = '${POLL_KEY}' LIMIT 1`);
const currentPage = (stateResult.rows && stateResult.rows.length > 0) ? parseInt(stateResult.rows[0].page) || 1 : 1;

// Fetch page from ST
let jobs = [], hasMore = false;
try {
  const jobsResp = await $helpers.httpRequest({
    method: 'GET',
    url: `https://api.servicetitan.io/jpm/v2/tenant/${ST_TENANT}/jobs?page=${currentPage}&pageSize=${PAGE_SIZE}&includeTotal=false&orderBy=id&orderByDirection=asc`,
    headers: { 'Authorization': `Bearer ${stToken}`, 'ST-App-Key': ST_APP_KEY },
    returnFullResponse: false
  });
  const jobsData = typeof jobsResp === 'string' ? JSON.parse(jobsResp) : jobsResp;
  jobs = jobsData.data || [];
  hasMore = jobs.length === PAGE_SIZE;
} catch(fetchErr) {
  console.log(`Page ${currentPage} fetch error: ${fetchErr.message}`);
}

// Pre-fetch customers
const customerIds = [...new Set(jobs.map(j => j.customerId).filter(Boolean))];
let customerMap = {};
if (customerIds.length > 0) {
  try {
    const idList = customerIds.map(id => `'${id}'`).join(',');
    const cr = await neonQuery(`SELECT st_customer_id, name, address, phone, email FROM spartan_ops.st_customers WHERE st_customer_id IN (${idList})`);
    if (cr.rows) for (const row of cr.rows) customerMap[row.st_customer_id] = row;
  } catch(e) { console.log('Customer lookup error: ' + e.message); }
}

let inserted = 0, skipped = 0, errors = 0;

for (const job of jobs) {
  try {
    const buId = String(job.businessUnitId || '');
    const jobTypeId = String(job.jobTypeId || '');
    if (EXCLUDED_BU_IDS.has(buId)) { skipped++; continue; }
    if (EXCLUDED_JOB_TYPE_IDS.has(jobTypeId)) { skipped++; continue; }

    const trackType = BU_TRACK_MAP[buId] || 'unknown';
    const stStatus = (job.status || '').toLowerCase();
    let status = 'active';
    if (['completed','done'].includes(stStatus)) status = 'completed';
    else if (['canceled','cancelled'].includes(stStatus)) status = 'cancelled';
    else if (stStatus === 'hold') status = 'on_hold';

    const cust = customerMap[String(job.customerId)] || {};
    const esc = s => (s || '').replace(/'/g, "''").substring(0, 500);
    const bookedAt = job.receivedOn ? `'${job.receivedOn}'` : 'NULL';
    const completedAt = job.completedOn ? `'${job.completedOn}'` : 'NULL';
    const schedDate = job.firstAppointmentDate ? `'${job.firstAppointmentDate.substring(0,10)}'` : 'NULL';
    const soldAmount = job.invoice?.total != null ? job.invoice.total : 'NULL';
    const isRecall = job.recallForJobId ? 'true' : 'false';
    const rawJson = JSON.stringify(job).replace(/'/g, "''");

    await neonQuery(`
      INSERT INTO spartan_ops.jobs (st_job_id, st_job_number, st_customer_id, customer_name, customer_address, customer_phone, customer_email, job_type, job_description, track_type, status, booked_at, install_completed_at, scheduled_install_date, sold_amount, is_recall, st_raw_data, created_at, updated_at)
      VALUES ('${job.id}', '${esc(job.jobNumber)}', '${job.customerId || ''}', '${esc(cust.name) || 'Unknown'}', '${esc(cust.address)}', '${esc(cust.phone)}', '${esc(cust.email)}', '${esc(job.type?.name || job.jobType?.name || '')}', '${esc((job.summary||'').substring(0,2000))}', '${trackType}', '${status}', ${bookedAt}, ${completedAt}, ${schedDate}, ${soldAmount}, ${isRecall}, '${rawJson}'::jsonb, NOW(), NOW())
      ON CONFLICT (st_job_id) DO UPDATE SET st_job_number=EXCLUDED.st_job_number, job_type=EXCLUDED.job_type, job_description=EXCLUDED.job_description, track_type=EXCLUDED.track_type, status=EXCLUDED.status, booked_at=EXCLUDED.booked_at, install_completed_at=EXCLUDED.install_completed_at, scheduled_install_date=EXCLUDED.scheduled_install_date, sold_amount=EXCLUDED.sold_amount, is_recall=EXCLUDED.is_recall, st_raw_data=EXCLUDED.st_raw_data, updated_at=NOW()
    `);
    inserted++;
  } catch(jobErr) {
    errors++;
    console.log(`Job ${job.id} error: ${jobErr.message}`);
  }
}

// ALWAYS advance cursor — this is the core fix
const nextPage = currentPage + 1;
await neonQuery(`
  INSERT INTO spartan_ops.poll_state (poll_key, last_poll_at, metadata)
  VALUES ('${POLL_KEY}', NOW(), '{"page": ${nextPage}}'::jsonb)
  ON CONFLICT (poll_key) DO UPDATE SET last_poll_at=NOW(), metadata='{"page": ${nextPage}}'::jsonb
`);

return [{ json: { page: currentPage, nextPage, jobsFetched: jobs.length, inserted, skipped, errors, hasMore, done: !hasMore } }];
